package document

import (
	"fmt"

	"github.com/gmrtd/gmrtd/utils"
)

// The variables below hold static sample data used to build SampleDocument.
// They are sourced from the ICAO 9303 Part-10 Appendix A worked examples
// (also used, independently, as happy-path test vectors under
// document/*_test.go), plus one real-world SOD/DSC/CSCA sample (AT) used
// elsewhere for passive-authentication tests. Because the data groups below
// come from different source documents, EF.SOD's hash list will NOT match
// these DG bytes and DG1's fictitious "UTO" MRZ country cannot be resolved -
// SampleDocument is for structural/UI use only. Callers that run Passive
// Authentication against it should expect (and can use as a worked example
// of) a failure result.

// EF.COM (9303-p10 worked example)
var sampleComBytes []byte = utils.HexToBytes("60145F0104303130365F36063034303030305C026175")

// EF.SOD (real-world AT sample, also used in TestNewSod)
var sampleSodBytes []byte = utils.HexToBytes("")

// DG1 - MRZ (9303-p10 TD2 worked example)
var sampleDg1Bytes []byte = utils.HexToBytes("614B5F1F48493C55544F4552494B53534F4E3C3C414E4E413C4D415249413C3C3C3C3C3C3C3C3C3C3C4432333134353839303755544F3734303831323246313230343135393C3C3C3C3C3C3C36")

// DG2 - Encoded Identification Features (Face), ISO 19794 (9303-p10 worked example)
var sampleDg2Bytes []byte = utils.HexToBytes("")

// DG7 - Displayed Signature or Usual Mark
var sampleDg7Bytes []byte = utils.HexToBytes("")

// DG11 - Additional Personal Detail(s) (9303-p10 A.5 worked example)
var sampleDg11Bytes []byte = utils.HexToBytes("6B605C0A5F0E5F115F425F125F135F0E0D534D4954483C3C4A4F484E3C4A5F110A414E59544F574E3C4D4E5F4217313233204D41504C452052443C414E59544F574E3C4D4E5F120B31363132353535313231325F130C54524156454C3C4147454E54")

// DG12 - Additional Document Detail(s) (adapted from an NZ passport)
var sampleDg12Bytes []byte = utils.HexToBytes("6C205C045F555F565F550E32303136313131353031333631325F56064E2D34393632")

// DG13 - Optional Detail(s) (non-TLV content)
var sampleDg13Bytes []byte = utils.HexToBytes("6D0A01234567890123456789")

// DG14 - Security Options (SecurityInfos incl. Chip Authentication)
var sampleDg14Bytes []byte = utils.HexToBytes("")

// DG15 - Active Authentication Public Key Info
var sampleDg15Bytes []byte = utils.HexToBytes("")

// DG16 - Person(s) to Notify (9303-p10 A.6 worked example)
var sampleDg16Bytes []byte = utils.HexToBytes("")

// SampleDocument returns a Document populated with static ICAO 9303 Part-10
// worked-example data (DG1, DG2, DG7, DG11-DG16, EF.COM, EF.SOD).
//
// It is intended for UI development/testing without a physical chip. The
// data groups are sourced from different worked examples, so running Passive
// Authentication against this Document is expected to fail (no ChipAuthResult
// is implied either).
func SampleDocument() (*Document, error) {
	var doc Document
	var err error

	if doc.Mf.Lds1.Com, err = NewCOM(sampleComBytes); err != nil {
		return nil, fmt.Errorf("[SampleDocument] NewCOM error: %w", err)
	}

	if doc.Mf.Lds1.Sod, err = NewSOD(sampleSodBytes); err != nil {
		return nil, fmt.Errorf("[SampleDocument] NewSOD error: %w", err)
	}

	dgBytes := map[int][]byte{
		1:  sampleDg1Bytes,
		2:  sampleDg2Bytes,
		7:  sampleDg7Bytes,
		11: sampleDg11Bytes,
		12: sampleDg12Bytes,
		13: sampleDg13Bytes,
		14: sampleDg14Bytes,
		15: sampleDg15Bytes,
		16: sampleDg16Bytes,
	}

	for _, dg := range []int{1, 2, 7, 11, 12, 13, 14, 15, 16} {
		if err = doc.NewDG(dg, dgBytes[dg]); err != nil {
			return nil, fmt.Errorf("[SampleDocument] NewDG(%d) error: %w", dg, err)
		}
	}

	return &doc, nil
}
